class Solution {
    public int numberOfSpecialChars(String word) {
        int n = word.length();
        int[] lowercase = new int[26];
        int[] uppercase = new int[26];
        int count = 0;
        for (int i = 0; i < n; i++) {
            char c = word.charAt(i);
            if (Character.isLowerCase(c)) {
                lowercase[c - 'a']++;
            } else {
                uppercase[c - 'a']++;
            }
        }
        for (int i = 0; i < 26; i++) {
            if (lowercase[i] > 0 && uppercase[i] > 0) {
                count++;
            }
        }
        return count;
    }
}
```

